import { describe, expect, it } from "vitest";
import { buildReplayCapabilityRecord } from "./detectCapabilities.js";
function status(overrides) {
    return {
        language: "typescript",
        packageName: "@bitfab/sdk",
        declaredVersion: null,
        resolvedVersion: "0.21.0",
        current: "0.21.0",
        latest: "0.21.0",
        latestSource: "remote",
        remoteCheckFailed: false,
        updateAvailable: false,
        manifestPath: "package.json",
        lockfilePath: "pnpm-lock.yaml",
        workspacePath: ".",
        renameFrom: null,
        deprecated: false,
        ...overrides,
    };
}
describe("buildReplayCapabilityRecord", () => {
    it("derives capabilities from the resolved version", () => {
        const record = buildReplayCapabilityRecord(status({ current: "0.21.0" }), "typescript");
        expect(record.versionResolved).toBe(true);
        expect(record.capabilities.supportsDatasetId).toBe(true);
        expect(record.capabilities.supportsInputAdapters).toBe(true);
    });
    it("flags an unresolved version and gates everything false", () => {
        const record = buildReplayCapabilityRecord(status({ resolvedVersion: null, current: null }), "python");
        expect(record.versionResolved).toBe(false);
        expect(Object.values(record.capabilities).every((v) => v === false)).toBe(true);
    });
    it("does not trust a manifest-only declared version (no lockfile/install)", () => {
        // resolvedVersion is null but a declared spec exists (current falls back to
        // it). Capabilities must stay unverified rather than trust the declared
        // spec, which is a range/lower-bound, not a confirmed install.
        const record = buildReplayCapabilityRecord(status({
            resolvedVersion: null,
            declaredVersion: "0.21.0",
            current: "0.21.0",
        }), "typescript");
        expect(record.versionResolved).toBe(false);
        expect(Object.values(record.capabilities).every((v) => v === false)).toBe(true);
        // The declared version is still surfaced for the upgrade hint.
        expect(record.current).toBe("0.21.0");
    });
    it("passes through version-update metadata for the upgrade step", () => {
        const record = buildReplayCapabilityRecord(status({
            resolvedVersion: "0.13.4",
            current: "0.13.4",
            latest: "0.21.0",
            updateAvailable: true,
            renameFrom: "bitfab",
            workspacePath: "packages/api",
        }), "typescript");
        expect(record.updateAvailable).toBe(true);
        expect(record.latest).toBe("0.21.0");
        expect(record.renameFrom).toBe("bitfab");
        expect(record.workspacePath).toBe("packages/api");
        // 0.13.4 predates replay trace IDs (0.13.5).
        expect(record.capabilities.supportsReplayTraceIds).toBe(false);
    });
});
